class Solution:
    def findSubstringInWraproundString(self, s):
        def ok(sub):
            for i in range(1, len(sub)):
                if (ord(sub[i]) - ord(sub[i - 1])) % 26 != 1:
                    return False
            return True
        found = set()
        n = len(s)
        for i in range(n):
            for j in range(i + 1, n + 1):
                sub = s[i:j]
                if ok(sub):
                    found.add(sub)
                else:
                    break
        return len(found)

