class Solution:
    def findSubstringInWraproundString(self, s):
        best = {}
        run = 0
        for i, ch in enumerate(s):
            if i > 0 and (ord(ch) - ord(s[i - 1])) % 26 == 1:
                run += 1
            else:
                run = 1
            if best.get(ch, 0) < run:
                best[ch] = run
        return sum(best.values())

